solutions.python:
class Solution:
    def minimumK(self, nums):
        def non_positive_ops(k):
            return sum((x + k - 1) // k for x in nums)

        lo, hi = 1, max(nums)
        while non_positive_ops(hi) > hi * hi:
            hi *= 2
        while lo < hi:
            mid = (lo + hi) // 2
            if non_positive_ops(mid) <= mid * mid:
                hi = mid
            else:
                lo = mid + 1
        return lo

solutions.javascript:
var minimumK = function(nums) {
    const nonPositiveOps = (k) => {
        let total = 0;
        for (const x of nums) total += Math.floor((x + k - 1) / k);
        return total;
    };

    let hiStart = nums[0];
    for (const x of nums) if (x > hiStart) hiStart = x;
    let lo = 1, hi = hiStart;
    while (nonPositiveOps(hi) > hi * hi) hi *= 2;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (nonPositiveOps(mid) <= mid * mid) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
